<script setup lang="ts">import{ref}from'vue';import{AlertTriangle,CheckCircle2,ChevronDown}from'lucide-vue-next';import type{CorrectionItem}from'@/types/course';const props=defineProps<{items:CorrectionItem[]}>();const emit=defineEmits<{complete:[]}>();const opened=ref<number[]>([]);function reveal(index:number){if(!opened.value.includes(index))opened.value.push(index);if(opened.value.length===props.items.length)emit('complete')}</script>
<template><section class="engine-card error-clinic"><header><span><AlertTriangle/></span><div><small>Error clinic</small><h3>Разбор типичных ошибок</h3><p>Сначала исправьте сами, затем откройте объяснение.</p></div></header><article v-for="(item,index) in items" :key="item.incorrect"><button @click="reveal(index)"><span><small>Ошибка {{index+1}}</small><s>{{item.incorrect}}</s></span><ChevronDown/></button><div v-if="opened.includes(index)" class="correction-answer"><CheckCircle2/><div><b>{{item.correct}}</b><p>{{item.explanation}}</p></div></div></article></section></template>